import{_ as e,p as l,q as a,a1 as i}from"./framework-e0dd9823.js";const o={},r=i('<h1 id="动词" tabindex="-1"><a class="header-anchor" href="#动词" aria-hidden="true">#</a> 动词</h1><p>动词就是表示动作或心理行为的词语</p><p>动词按照作用可以分为谓语动词和非谓语动词</p><h2 id="谓语动词" tabindex="-1"><a class="header-anchor" href="#谓语动词" aria-hidden="true">#</a> 谓语动词</h2><ol><li>实义动词：有实际意义的动词，也就是有实际动作和心里行为。</li></ol><p>实义动词分为及物动词和不及物动词。及物动词就是必须有宾语的实义动词，例如：</p><ul><li>I buy a book.</li></ul><p>不及物动词就是不能用实义动词</p><ul><li>I work.</li></ul><p>实义动词有五种格式：分别是原型，过去式，过去分词，现在分词，第三人称单数的格式。例如：work（原型），worked（过去式），worked（过去分词），working（现在分词），works（第三人称单数）。为什么要有这么格式呢，因为英语的动词主要是谓语的作用，通过对谓语动词的变换来表表达出不同的意思。</p><ol start="2"><li>系动词： 也叫连系动词，跟表语构成状态型谓语，最常见的系动词是 be</li></ol><p>系动词只有一个作用，那就是跟表语构成“系表结构” 做状态型谓语。系动词是不能单数使用的，必须跟表语一起用。最常见的系动词就是 be ，系动词在句子的意思是“是”。be 动词总共有八种格式。分别是 be、am、is、are、was、were、been、being。</p><ul><li>I will be a teacher.</li><li>I am a teacher.</li><li>She is a teacher.</li><li>Your are a thacher.</li><li>He was a thacher before.</li><li>They were thachers bofore.</li><li>I have been a thacher for three yaras.</li><li>being a thacher.</li></ul><p>be 用于将来时态，am/is/are 用于一般现在时态，was/were 用于一般过去时态，been 用于完成时态和被动语态。</p><p>除了“be”，还有一些其他的系动词，但这些系动词不是专门的，而是从实义动词借过来临时充当系动词用的。当这个实习用词被用来偶系动词的时候，原本意思就发生变化，并且只能跟形容词做表语。</p><p>例如：“look”原本意思是“看”，有时候可以充当一个系动词，表示“看起来”。</p><ul><li>You look beauriful.</li></ul><p>常见的系动词：keep/look/smell/taste/sound/fell/seem/become/get</p><ol start="3"><li>助动词：也叫结构助动词，帮助实义动词和系动词构成符合谓语结构，一般没有意思。也没有专门的助动词，他都是从其他动词里面借过来的。</li></ol><ul><li>I am working now. (“am”就使从系动词借过来的助动词，没有意思，构成现在进行时态)</li><li>Do you love me? (do 构成一般疑问句)</li><li>I do not love you. (do 构成否定句)</li><li>I have learned English for the years. (have 构成现在完成时态)</li></ul><ol start="4"><li>情态动词：跟实义动词原型和系动词原型构成复合谓语，有意义。并且有专门的情态动词。情态动词必须跟实义动词和系动词原型，不能跟其他格式。</li></ol><p>常见的情态动词有：can/could/may/might/should/must/have to/dare/needn&#39;t/had better/ought to</p><ul><li>I must earn money every day.</li><li>I can help you.</li><li>I can be a good teacher.</li></ul>',23),t=[r];function h(s,n){return l(),a("div",null,t)}const u=e(o,[["render",h],["__file","verb.html.vue"]]);export{u as default};
